const event = $json.event && typeof $json.event === 'object' ? $json.event : {};
const session = $json.session && typeof $json.session === 'object' ? $json.session : {};
const callbackData = String(event.callback_query?.data ?? '').trim();
const reply_text = callbackData === 'confirm_exchange'
  ? 'Exchange confirmed. Admin has been notified and we will follow up with the details.'
  : callbackData === 'cancel_exchange'
  ? 'Exchange canceled. Let me know if you want another option.'
  : 'I did not recognize that action. Please try again.';
const updatedSession = {
  ...session,
  last_message_at: Date.now(),
  message_count: Math.max(0, Number(session.message_count ?? 0)) + 1,
  admin_escalation: callbackData === 'confirm_exchange'
    ? { required: true, reason: 'exchange_confirmed', status: 'pending' }
    : (session.admin_escalation && typeof session.admin_escalation === 'object' ? session.admin_escalation : { required: false, reason: null, status: null }),
  exchange_details: {
    ...(session.exchange_details || {}),
    last_callback_action: callbackData,
    confirmed_at: callbackData === 'confirm_exchange' ? Date.now() : (session.exchange_details?.confirmed_at ?? null),
    current_interest: session.flow_context?.buy_flow?.current_interest ?? null,
  },
};
return [{
  json: {
    event,
    session,
    callbackData,
    reply_text,
    telegram_payload: { chat_id: event.chatId ?? null, text: reply_text },
    session_update_payload: { userId: event.userId ?? null, chatId: event.chatId ?? null, session: updatedSession },
    admin_notification_payload: callbackData === 'confirm_exchange'
      ? { customer_id: session.customer_id ?? event.userId ?? null, chat_id: event.chatId ?? null, action: 'confirm_exchange', exchange_details: updatedSession.exchange_details }
      : null,
  },
}];
